import React from "react";
import { Routes, Route, Navigate } from "react-router-dom";

import Home from "../pages/Home";
import Login from "../pages/Auth/Login";
import Register from "../pages/Auth/Register";

import VehicleList from "../pages/Vehicles/VehicleList";
import AddVehicle from "../pages/Vehicles/AddVehicle";
import EditVehicle from "../pages/Vehicles/EditVehicle";

import LeadList from "../pages/Leads/LeadList";
import AddLead from "../pages/Leads/AddLead";
import EditLead from "../pages/Leads/EditLead";

import AppointmentList from "../pages/Appointments/AppointmentList";
import AddAppointment from "../pages/Appointments/AddAppointment";
import EditAppointment from "../pages/Appointments/EditAppointment";
import CreateStaff from "../pages/Admin/CreateStaff";

import CustomerBookAppointment from "../pages/Appointments/CustomerBookAppointment";
import MyAppointments from "../pages/Appointments/MyAppointments";
import EditMyAppointment from "../pages/Appointments/EditMyAppointment";

import SaleList from "../pages/Sales/SaleList";
import AddSale from "../pages/Sales/AddSale";
import EditSale from "../pages/Sales/EditSales";

// ✅ change this to the real file you have:
import DocumentList from "../pages/Documents/DocumentList";

import StaffList from "../pages/Admin/StaffList";
import EditStaff from "../pages/Admin/EditStaff";
import AdminDashboard from "../pages/Admin/AdminDashboard";
import RequireAuth from "../components/RequireAuth";
import AdminOrPublicLayout from "../components/AdminOrPublicLayout";
import AdminLayout from "../components/AdminLayout";

//Document
import AddDocument from "../pages/Documents/AddDocument";
import EditDocument from "../pages/Documents/EditDocument";

function AppRoutes() {
  return (
    <Routes>
      <Route path="/" element={<Home />} />

      {/* Vehicle Routes - Wrap with AdminOrPublicLayout for sidebar in admin/manager/staff roles */}
      <Route path="/vehicles/add" element={<AdminOrPublicLayout><AddVehicle /></AdminOrPublicLayout>} />
      <Route path="/vehicles/edit/:id" element={<AdminOrPublicLayout><EditVehicle /></AdminOrPublicLayout>} />
      <Route path="/vehicles" element={<AdminOrPublicLayout><VehicleList /></AdminOrPublicLayout>} />

      {/* Lead Routes - Wrap with AdminOrPublicLayout */}
      <Route path="/leads" element={<AdminOrPublicLayout><LeadList /></AdminOrPublicLayout>} />
      <Route path="/leads/add" element={<AdminOrPublicLayout><AddLead /></AdminOrPublicLayout>} />
      <Route path="/leads/edit/:id" element={<AdminOrPublicLayout><EditLead /></AdminOrPublicLayout>} />

      {/* Appointment Routes - Wrap with AdminOrPublicLayout */}
      <Route path="/appointments" element={<AdminOrPublicLayout><AppointmentList /></AdminOrPublicLayout>} />
      <Route path="/appointments/add" element={<AdminOrPublicLayout><AddAppointment /></AdminOrPublicLayout>} />
      <Route path="/appointments/edit/:id" element={<AdminOrPublicLayout><EditAppointment /></AdminOrPublicLayout>} />

      {/* Admin Only Routes - Wrap with AdminLayout */}
      <Route path="/admin/create-staff" element={<RequireAuth roles={["admin"]}>
        <AdminLayout><CreateStaff /></AdminLayout>
      </RequireAuth>} />

      {/* Public Customer Routes - No layout wrapper */}
      <Route path="/book-appointment" element={<CustomerBookAppointment />} />
      <Route path="/my-appointments" element={<MyAppointments />} />
      <Route path="/edit-my-appointment/:id" element={<EditMyAppointment />} />

      {/* Sales Routes - Wrap with AdminOrPublicLayout */}
      <Route path="/sales" element={<AdminOrPublicLayout><SaleList /></AdminOrPublicLayout>} />
      <Route path="/sales/add" element={<AdminOrPublicLayout><AddSale /></AdminOrPublicLayout>} />
      <Route path="/sales/edit/:id" element={<AdminOrPublicLayout><EditSale /></AdminOrPublicLayout>} />

      {/* Document Routes - Wrap with AdminOrPublicLayout */}
      <Route path="/documents" element={<AdminOrPublicLayout><DocumentList /></AdminOrPublicLayout>} />
      <Route path="/documents/add" element={<AdminOrPublicLayout><AddDocument /></AdminOrPublicLayout>} />
      <Route path="/documents/edit/:id" element={<AdminOrPublicLayout><EditDocument /></AdminOrPublicLayout>} />

      {/* Auth Routes - No layout */}
      <Route path="/login" element={<Login />} />
      <Route path="/register" element={<Register />} />

      {/* Admin Dashboard & Staff Management - Wrap with AdminLayout */}
      <Route path="/admin/dashboard" element={<RequireAuth roles={["admin", "manager"]}>
        <AdminLayout><AdminDashboard /></AdminLayout>
      </RequireAuth>} />
      <Route path="/admin/staff" element={<RequireAuth roles={["admin"]}>
        <AdminLayout><StaffList /></AdminLayout>
      </RequireAuth>} />
      <Route path="/admin/staff/edit/:id" element={<RequireAuth roles={["admin"]}>
        <AdminLayout><EditStaff /></AdminLayout>
      </RequireAuth>} />

      <Route path="*" element={<Navigate to="/" />} />
    </Routes>
  );
}

export default AppRoutes;
